class Solution {public: int change(int amount, vector<int>& coins) {
        int dp[amount + 1];
        for (int i = 0; i <= amount; i++) {
            if (i == 0) dp[i] = 1;
            else if (coins.size() == 0) dp[i] = 0;
            else if (coins[0] > i) dp[i] = dp[i];
            else dp[i] = dp[i - coins[0]] + dp[i];
        }
        return dp[amount];
    }};

